void unreachableExample() {
    bool a = false;
    if (a) {  // Noncompliant - condition is always false
        doSomething(); // never executed
    }

    if (!a || b) { // Noncompliant - '!a' is always true, 'b' is never evaluated
        doSomething();
    } else {
        doSomethingElse(); // never executed
    }
}

void alwaysTrue() {
    if (true) { // Noncompliant - condition is always true
        doSomething();
    } else {
        doSomethingElse(); // never executed
    }
}

compliant:
void reachableExample() {
    bool a = getValue(); // Dynamic value
    if (a) { // Compliant - condition can be true or false
        doSomething();
    }

    if (a && someCondition()) { // Compliant - both conditions are evaluated
        doSomething();
    } else {
        doSomethingElse();
    }
}

void properConditional() {
    int value = calculateValue();
    if (value > 0) { // Compliant - condition depends on runtime value
        doSomething();
    } else {
        doSomethingElse();
    }
}
